return items.map(item => {
  const raw = (item.json.email || '').toLowerCase();
  const safeEmail = raw.replace(/[^a-z0-9]/g, '-').substring(0, 30);
  const ts = Date.now();
  const candidateId = `CAND-${ts}-${safeEmail}`;

  return {
    json: {
      full_name: item.json.full_name || '',
      email: item.json.email || '',
      phone: item.json.phone || '',
      linkedin_url: item.json.linkedin_url || '',
      portfolio_url: item.json.portfolio_url || '',
      candidate_id: candidateId,
      created_at: new Date().toISOString(),
      stage: 'Applied',
      workflow_version: 'v3'
    },
    binary: item.binary
  };
});

return items.map(item => {
  const binaryData = item.binary || {};
  const keys = Object.keys(binaryData);

  if (keys.length === 0) {
    throw new Error(`No file uploaded for candidate: ${item.json.email || 'unknown'}`);
  }

  const firstKey = keys[0];
  const fileMeta = binaryData[firstKey];

  const mimeType = fileMeta.mimeType || '';
  if (mimeType && !mimeType.includes('pdf')) {
    throw new Error(`Invalid file type: ${mimeType}. Only PDF is accepted.`);
  }

  return {
    json: item.json,
    binary: {
      resume_file: fileMeta
    }
  };
});

const driveResponse = items[0].json;
const candidateData = $('02 | Generate Candidate ID').first().json;

if (!driveResponse.id) {
  throw new Error('Google Drive upload did not return a file ID.');
}

return [{
  json: {
    ...candidateData,
    drive_resume_link: driveResponse.webViewLink || '',
    drive_file_id: driveResponse.id || '',
    drive_file_name: driveResponse.name || ''
  }
}];

return items.map(item => {
  const binaryData = item.binary || {};
  const keys = Object.keys(binaryData);

  if (keys.length === 0) {
    const candidateId = $('06 | Merge Candidate and Drive Data').first().json.candidate_id || 'unknown';
    throw new Error(`Resume download returned no binary data for candidate: ${candidateId}`);
  }

  const firstKey = keys[0];

  return {
    json: item.json,
    binary: {
      resume_pdf: binaryData[firstKey]
    }
  };
});

