const formData = $('19 | Questionnaire Form').first().json;
const candidateData = $('21 | Lookup Candidate Data').first().json;

const q1 = formData['Q1: Explain the difference between REST and GraphQL APIs. When would you choose one over the other? (20 marks)'] || '';
const q2 = formData['Q2: Describe how you would optimize a slow database query. What tools and techniques would you use? (20 marks)'] || '';
const q3 = formData['Q3: How would you design a scalable microservices architecture for an e-commerce platform? (20 marks)'] || '';
const q4 = formData['Q4: Explain your approach to debugging a production issue where users report intermittent failures. (20 marks)'] || '';
const q5 = formData['Q5: What is your experience with CI/CD pipelines? Describe a pipeline you have built or worked with. (20 marks)'] || '';

const responses = `
Q1 (REST vs GraphQL - 20 marks):
${q1}

Q2 (Database Query Optimization - 20 marks):
${q2}

Q3 (Microservices Architecture Design - 20 marks):
${q3}

Q4 (Production Debugging Approach - 20 marks):
${q4}

Q5 (CI/CD Pipeline Experience - 20 marks):
${q5}`;

return [{
  json: {
    candidate_id: candidateData.candidate_id || 'N/A',
    full_name: formData['Full Name'],
    email: formData.Email,
    questionnaire_responses: responses,
    resume_score: candidateData.score || 0,
    resume_summary: candidateData.summary || ''
  }
}];

const aiOutput = $json.output?.[0]?.content?.[0]?.text || {};
const promptData = $('22 | Build Evaluation Prompt').first().json;

return [{
  json: {
    candidate_id: promptData.candidate_id,
    full_name: promptData.full_name,
    email: promptData.email,

    questionnaire_responses: promptData.questionnaire_responses,

    questionnaire_score: aiOutput.questionnaire_score || 0,
    q1_score: aiOutput.q1_score || 0,
    q2_score: aiOutput.q2_score || 0,
    q3_score: aiOutput.q3_score || 0,
    q4_score: aiOutput.q4_score || 0,
    q5_score: aiOutput.q5_score || 0,
    phone_interview_notes: aiOutput.phone_interview_notes || '',
    phone_screening_result: aiOutput.phone_screening_result || '',
    recruiter_notes: aiOutput.recruiter_notes || '',
    recommended_stage: aiOutput.recommended_stage || 'Manual Review',

    updated_at: new Date().toISOString(),
    scored_at: new Date().toISOString(),
    workflow_version: 'v8'
  }
}];

